-- Adds the expanded Oculi demo catalog used by the map, feed, search, uploads,
-- place detail pages, and photographer profiles.
insert into public.oculi_demo_catalog_items (kind, item_id, payload, updated_at)
select 'user', value->>'id', value, now()
from jsonb_array_elements($oculi_user$[
  {"id":"user-zoe","name":"Zoe Kim","username":"@zoekim.photo","avatarUrl":"/generated/avatar-zoe-kim.png","bio":"Gardens, quiet museums, and soft botanical light.","homeArea":"Inner Richmond","followerCount":1740,"followingCount":298},
  {"id":"user-marcus","name":"Marcus Lee","username":"@marcusframes","avatarUrl":"/generated/avatar-marcus-lee.png","bio":"Transit lines, long shadows, and downtown geometry.","homeArea":"SoMa","followerCount":1325,"followingCount":221},
  {"id":"user-ava","name":"Ava Thompson","username":"@ava.coast","avatarUrl":"/generated/avatar-ava-thompson.png","bio":"Coastal hikes, beaches, and weather that makes a frame.","homeArea":"Pacifica","followerCount":2480,"followingCount":355,"isInfluencer":true},
  {"id":"user-diego","name":"Diego Alvarez","username":"@diego.nights","avatarUrl":"/generated/avatar-diego-alvarez.png","bio":"Night color, neon, diners, and handheld street sets.","homeArea":"Lower Haight","followerCount":1168,"followingCount":409}
]$oculi_user$::jsonb) as value
on conflict (kind, item_id) do update
set payload = excluded.payload,
    updated_at = excluded.updated_at;

insert into public.oculi_demo_catalog_items (kind, item_id, payload, updated_at)
