  {"id":"ferry-plaza-market","areaId":"sf","name":"Ferry Plaza Market","description":"Produce color, vendor motion, bay-facing light, and easy documentary frames.","lat":37.7956,"lng":-122.3933,"fuzzyLocationLabel":"Ferry Building plaza","navigationAddress":"Ferry Plaza Farmers Market, 1 Ferry Building, San Francisco, CA","timCurated":false,"saveCount":365,"recentActivityScore":82,"bestTimes":["Morning","Daylight","Rainy evenings"],"tags":["street","food","color","waterfront"],"coverPhotoUrl":"/generated/ferry-plaza-market.png"},
