  {"id":"haight-ashbury","areaId":"sf","name":"Haight-Ashbury Storefronts","description":"Vintage signage, saturated facades, sidewalk portraits, and layered street color.","lat":37.7692,"lng":-122.4481,"fuzzyLocationLabel":"Haight Street corridor","navigationAddress":"Haight St & Ashbury St, San Francisco, CA","timCurated":false,"saveCount":398,"recentActivityScore":78,"bestTimes":["Daylight","Late afternoon","Night"],"tags":["street","color","portraits","night"],"coverPhotoUrl":"/generated/haight-ashbury.png"},
